Example: 

```
node {
  output: "a"
  op_type: "Constant"
  attribute {
    name: "value"
    t {
      data_type: INT32
      int32_data: 3
      name: "three"
    }
    type: TENSOR
  }
}
node {
  output: "b"
  op_type: "Constant"
  attribute {
    name: "value"
    t {
      data_type: INT32
      int32_data: 6
      name: "three"
    }
    type: TENSOR
  }
}
node {
  output: "keepgoing"
  op_type: "Constant"
  attribute {
    name: "value"
    t {
      data_type: BOOL
      int32_data: 1
      name: "three"
    }
    type: TENSOR
  }
}
node {
  output: "max_trip_count"
  op_type: "Constant"
  attribute {
    name: "value"
    t {
      data_type: INT32
      int32_data: 10
      name: "three"
    }
    type: TENSOR
  }
}
node {
  input: "max_trip_count"
  input: "b"
  input: "keepgoing"
  op_type: "DoWhile"
  attribute {
    name: "body"
    g {
      node {
        input: "a"
        input: "b"
        output: "my_local"
        op_type: "Add"
      }
      node {
        input: "a"
        input: "b"
        output: "b_out"
        op_type: "Sub"
      }
      node {
        input: "my_local"
        input: "b"
        output: "keepgoing_out"
        op_type: "Greater"
      }
      node {
        input: "b"
        input: "b"
        output: "user_defined_vals"
        op_type: "Add"
      }
      name: "body-net"
      input {
        name: "b"
        type {
          tensor_type {
            elem_type: INT32
            shape {
            }
          }
        }
      }
      input {
        name: "keepgoing"
        type {
          tensor_type {
            elem_type: BOOL
            shape {
            }
          }
        }
      }
      output {
        name: "b_out"
        type {
          tensor_type {
            elem_type: INT32
            shape {
            }
          }
        }
      }
      output {
        name: "keepgoing_out"
        type {
          tensor_type {
            elem_type: BOOL
            shape {
            }
          }
        }
      }
      output {
        name: "user_defined_vals"
        type {
          tensor_type {
            elem_type: INT32
            shape {
            }
          }
        }
      }
    }
    type: GRAPH
  }
}
name: "predict-net"
```
Before:

```
graph predict-net {
  %a = Constant[value = <Tensor>]()
  %b = Constant[value = <Tensor>]()
  %keepgoing = Constant[value = <Tensor>]()
  %max_trip_count = Constant[value = <Tensor>]()
  DoWhile[body = <Unknown>](%max_trip_count, %b, %keepgoing)
  return
}
```

After: 

```
graph predict-net {
  %a = Constant[value = <Scalar Tensor [3]>]()
  %b = Constant[value = <Scalar Tensor [6]>]()
  %keepgoing = Constant[value = <Scalar Tensor [1]>]()
  %max_trip_count = Constant[value = <Scalar Tensor [10]>]()
  DoWhile[body = <graph body-net>](%max_trip_count, %b, %keepgoing)
  return
}

graph body-net (
  %b[INT32, scalar]
  %keepgoing[BOOL, scalar]
) {
  %my_local = Add(%a, %b)
  %b_out = Sub(%a, %b)
  %keepgoing_out = Greater(%my_local, %b)
  %user_defined_vals = Add(%b, %b)
  return %b_out, %keepgoing_out, %user_defined_vals
}
```
